def range_summary(nums):
    if not nums:
        return ''

    distinct_nums = sorted(set(nums))
    result = []
    current_run = [distinct_nums[0]]

    for num in distinct_nums[1:]:
        if num == current_run[-1] + 1:
            current_run.append(num)
        else:
            if len(current_run) > 1:
                result.append(f'{current_run[0]}-{current_run[-1]}')
            else:
                result.append(str(current_run[0]))
            current_run = [num]

    if len(current_run) > 1:
        result.append(f'{current_run[0]}-{current_run[-1]}')
    else:
        result.append(str(current_run[0]))

    return ','.join(result)
